        com.varabyte.kobweb.silk.init.initSilkWidgets(ctx)
        com.varabyte.kobweb.silk.init.initSilkWidgetsKobweb(ctx)
        ctx.theme.registerStyle("headline-text", id.neotica.alexandria.HeadlineTextStyle)
        ctx.theme.registerStyle("subheadline-text", id.neotica.alexandria.SubheadlineTextStyle)
        ctx.theme.registerStyle("markdown", id.neotica.alexandria.components.layouts.MarkdownStyle)
