import kotlinx.serialization.json.Json
import org.jetbrains.compose.web.css.cssRem

@InitRoute() // Match this with your @Page path if you define it explicitly
fun initChapterPage(ctx: InitRouteContext) {
    ctx.data.add(NeoLayoutData("Alexandria", "/alexandria")) // Set your desired tab title here
}

@Page
@Composable
@Layout(".components.layouts.NeoPageLayout")
fun ChapterPage() {
    val ctx = rememberPageContext()
    var checkString by remember { mutableStateOf("Loading...") }
    var book by remember { mutableStateOf<ApiResult<Book>>(ApiResult.Loading()) }

    val bookId by remember(ctx) { mutableStateOf(ctx.route.params["bookId"]) }

    LaunchedEffect(Unit) {
        try {
            val response = window.fetch("$baseUrl/alexandria/$bookId").await()
            val jsonText = response.text().await()


            if (response.ok) {
                val json = Json {
                    ignoreUnknownKeys
                }
                val two = json.decodeFromString<Book>(jsonText)
                book = ApiResult.Success(two)
            } else {
                book = ApiResult.Error(response.statusText)
            }
        } catch (e: Exception) {
            book = ApiResult.Error(e.toString())
        }
    }

    Box(
        modifier = Modifier
            .backgroundColor(NeoColor.backgroundPrimary)
            .fillMaxSize()
            .padding(leftRight = 2.cssRem)
            .overflow(Overflow.Auto)
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
        ) {
            SpanText("Alexandria")
            SpanText(bookId.toString())
            if (book.data != null) {
                book.data?.let {book ->
                    SpanText(book.title)
                    SpanText("Chapters:")
                    book.chapters!!.forEach {
                        Link("/book/content/${it.id}") {
                            SpanText(it.title)
                        }
                    }
                }


            }

        }
    }
}