@InitRoute() // Match this with your @Page path if you define it explicitly
fun initContentPage(ctx: InitRouteContext) {
    ctx.data.add(NeoLayoutData("Alexandria", "/alexandria")) // Set your desired tab title here
}

@Page
@Composable
@Layout(".components.layouts.NeoPageLayout")
fun ContentPage() {
    val ctx = rememberPageContext()
    var checkString by remember { mutableStateOf("Loading...") }
    var content by remember { mutableStateOf<ApiResult<Chapter>>(ApiResult.Loading()) }

    val id by remember(ctx) { mutableStateOf(ctx.route.params["chapterId"]) }

    LaunchedEffect(Unit) {
        try {
            val response = window.fetch("$baseUrl/alexandria/chapters/contents/full/$id").await()
            val jsonText = response.text().await()


            if (response.ok) {
                val json = Json {
                    ignoreUnknownKeys
                }
                val two = json.decodeFromString<Chapter>(jsonText)
                content = ApiResult.Success(two)
            } else {
                content = ApiResult.Error(response.statusText)
            }
        } catch (e: Exception) {
            content = ApiResult.Error(e.toString())
        }
    }

    Box(
        modifier = Modifier
            .backgroundColor(NeoColor.backgroundPrimary)
            .fillMaxSize()
            .padding(leftRight = 2.cssRem)
            .overflow(Overflow.Auto)
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
        ) {
            content.errorMessage?.let {
                SpanText(it)
            }
            if (content.data != null) {
                content.data?.let {
                    Row {
                        SpanText(
                            text = it.content.toString(),
                            modifier = Modifier
//                                .weight(3)
                                .color(NeoColor.primary)
                        )
                        Column(
                            Modifier
                                .padding(leftRight = 2.cssRem)
                        ) {
                            SpanText(
                                text = it.title,
                                modifier = Modifier
                                    .whiteSpace(WhiteSpace.NoWrap)
                            )
                        }

                    }

                }
            }
        }
    }
}