    base { Modifier.fillMaxWidth().gap(2.cssRem) }
    Breakpoint.MD { Modifier.margin { top(20.vh) } }
}

// A demo grid that appears on the homepage because it looks good
val HomeGridStyle = CssStyle.base {
    Modifier
        .gap(0.5.cssRem)
        .width(70.cssRem)
        .height(18.cssRem)
}

private val GridCellColorVar by StyleVariable<Color>()
val HomeGridCellStyle = CssStyle.base {
    Modifier
        .backgroundColor(GridCellColorVar.value())
        .boxShadow(blurRadius = 0.6.cssRem, color = GridCellColorVar.value())
        .borderRadius(1.cssRem)
}


@InitRoute
fun initHomePage(ctx: InitRouteContext) {
    ctx.data.add(NeoLayoutData("Home"))
}

@Page
@Layout(".components.layouts.NeoPageLayout")
@Composable
fun HomePage() {
    var checkString by remember { mutableStateOf("") }
    var bookList by remember { mutableStateOf<ApiResult<Pagination<Book>>>(ApiResult.Loading()) }

    LaunchedEffect(Unit) {
        try {
            val response = window.fetch("$baseUrl/alexandria").await()
            val jsonText = response.text().await()


            if (response.ok) {
                val json = Json {
                    ignoreUnknownKeys
                }
                val two = json.decodeFromString<Pagination<Book>>(jsonText)
                bookList = ApiResult.Success(two)
            } else {
                bookList = ApiResult.Error(response.statusText)
            }
        } catch (e: Exception) {
            bookList = ApiResult.Error(e.toString())
        }
    }

    Box(
        modifier = Modifier
            .backgroundColor(NeoColor.backgroundPrimary)
            .fillMaxSize()
            .padding(leftRight = 2.cssRem)
            .overflow(Overflow.Auto)
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
        ) {
            SpanText("Home")
//            Link("/alexandria") {
//                SpanText("Alexandria")
//            }
            SpanText("\uD83D\uDEA7 This site is still being constructed. \uD83D\uDEA7")
            SpanText("yuep")
            SpanText(checkString)
            SpanText(bookList.data?.content?.first()?.author.toString())
            if (bookList.data != null) {
                bookList.data!!.content.forEach {
                    Link("/book?bookId=${it.id}") {
                        SpanText(it.title)
                    }
                }
            }
        }
    }
}
